var $bm_rt;
var freq, amp, decay, n, n, t, v, speed, bounce, dims, dir, dir, dir;
freq = effect('Bounce Frequency')('Slider');
amp = effect('Bounce Amplitude')('Slider');
decay = effect('Bounce Decay')('Slider');
$bm_rt = n = 0;
if (numKeys > 0) {
    $bm_rt = n = nearestKey(time).index;
    if (key(n).time > time) {
        n--;
    }
}
if (n <= 0) {
    $bm_rt = value;
} else {
    $bm_rt = t = $bm_sub(time, key(n).time);
    if (t < 0) {
        $bm_rt = value;
    } else {
        v = velocityAtTime($bm_sub(key(n).time, $bm_div(thisComp.frameDuration, 10)));
        speed = length(v);
        bounce = $bm_div($bm_mul($bm_div($bm_mul(speed, amp), 100), Math.sin($bm_mul($bm_mul($bm_mul(freq, t), 2), Math.PI))), Math.exp($bm_mul(decay, t)));
        dims = value.length;
        if (speed > 0.0001) {
            dir = normalize(v);
        } else if (dims == 3) {
            dir = [
                0,
                0,
                0
            ];
        } else {
            dir = [
                0,
                0
            ];
        }
        $bm_rt = $bm_sum(value, $bm_mul(dir, bounce));
    }
}

